Here's a complete test class using modern MSTest (v3+) patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // MSTest 3.x+ injects a CancellationToken that respects [Timeout].
    // Returning Task (not void) is required for proper async support.

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ReturnsContent_OnSuccess(CancellationToken cancellationToken)
    {
        var handler = new MockHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com", cancellationToken);

        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_OnNonSuccessStatusCode(CancellationToken cancellationToken)
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com", cancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal mock handler to avoid external mocking libraries
    private sealed class MockHttpMessageHandler(string content, HttpStatusCode statusCode)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(statusCode)
            {
                Content = new StringContent(content)
            });
        }
    }
}
```

**Key modern MSTest patterns used:**

| Pattern | Detail |
|---|---|
| **`async Task` return** | Never use `async void`; MSTest only tracks `Task`-returning methods |
| **`CancellationToken` parameter** | MSTest 3.x+ auto-injects a token wired to `[Timeout]` |
| **`[Timeout]`** | Cancels the injected token on expiry — no manual `CancellationTokenSource` needed for timeouts |
| **Custom `HttpMessageHandler`** | Avoids mocking `HttpClient` directly (its methods aren't virtual) |

The injected `CancellationToken` is the biggest modernization — it replaces the older pattern of manually creating a `CancellationTokenSource` with a timer for timeout enforcement.
